["Nameplate Removed"] = "function(self, unitId, unitFrame, envTable)\n    envTable.UpdateBorder(unitFrame, false)\nend",
["Cast Start"] = "function(self, unitId, unitFrame, envTable)\n    envTable.UpdateIconPosition(unitFrame)\n    envTable.UpdateBorder(unitFrame, true)\nend",
["Cast Update"] = "function(self, unitId, unitFrame, envTable)\n    envTable.UpdateIconPosition(unitFrame)\nend",
["Constructor"] = "function(self, unitId, unitFrame, envTable)\n    \n    -- Last update by Luckyone: August 10, 2025\n    \n    -- This is the Plater setting \"Cast Bar -> Show Icon\"\n    envTable.ShowIcon = Plater.db.profile.castbar_icon_show\n    \n    local castBar = unitFrame.castBar\n    local healthBar = unitFrame.healthBar\n    local icon = castBar.Icon\n    local shield = castBar.BorderShield\n    \n    function envTable.UpdateIconPosition(unitFrame)\n        -- Remove the shield for uninterruptible casts\n        -- We color the uninterruptible castbar red\n        shield:Hide()\n        \n        if envTable.ShowIcon then -- The option is enabled, icon should be displayed\n            if not icon then return end\n            icon:ClearAllPoints()\n            PixelUtil.SetPoint(icon, 'TOPLEFT', healthBar, 'BOTTOMLEFT', 0, 0)\n            icon:SetHeight(8)\n            icon:SetWidth(8)\n            icon:Show()\n        else -- The option is disabled, icon should be hidden\n            icon:Hide()\n        end\n    end\n    \n    function envTable.UpdateBorder(unitFrame, casting)\n        if casting then\n            -- This is our border while castbar is shown\n            healthBar.border:ClearAllPoints()\n            PixelUtil.SetPoint(healthBar.border, 'TOPLEFT', healthBar, 'TOPLEFT', 0, 0)\n            PixelUtil.SetPoint(healthBar.border, 'BOTTOMRIGHT', castBar, 'BOTTOMRIGHT', 0, 0)\n        else\n            -- This is our border while castbar is hidden\n            healthBar.border:ClearAllPoints()\n            PixelUtil.SetPoint(healthBar.border, 'TOPLEFT', healthBar, 'TOPLEFT', 0, 0)\n            PixelUtil.SetPoint(healthBar.border, 'BOTTOMRIGHT', healthBar, 'BOTTOMRIGHT', 0, 0)\n        end\n    end\n    -- Make sure we don't hook over and over\n    if not unitFrame.castBar.borderChangeHooked then\n        hooksecurefunc(unitFrame.castBar, 'Hide', function() envTable.UpdateBorder(unitFrame, false) end)\n        unitFrame.castBar.borderChangeHooked = true\n    end\nend",
},
