["Nameplate Added"] = "function (self, unitId, unitFrame, envTable, modTable)\n    local minionScale = modTable.config.minionScale\n    local minusScale = modTable.config.minusScale\n    local levelScale = modTable.config.levelDifferenceScale\n    \n    local scale = 1\n    \n    if minionScale ~= 1 and UnitIsMinion(unitId) then\n        scale = minionScale\n    elseif minusScale ~= 1 and UnitClassification(unitId) == \"minus\" then\n        scale = minusScale\n    elseif UnitEffectiveLevel(\"player\") - UnitEffectiveLevel(unitId) == 2 then\n        scale = levelScale\n    end\n    \n    Plater.SetNameplateScale(unitFrame, scale)\nend",
},
